window.bookTitle = function(book, locale) {
  const L = locale || window.__lg_locale || "en";
  const map = window.LG_BOOK_TITLES[book.id];
  if (map && map[L]) return map[L];
  if (map && map.en) return map.en;
  // Fallback to whatever is on the book object.
  if ((L === "zh-CN" || L === "zh-TW" || L === "ja" || L === "ko") && book.titleZh) return book.titleZh;
  return book.title;
};

